// Process Dify response
const body = $input.first().json || {};
const webhookInput = $input.all()[1]?.json || {};

const answer = body.answer || '';
const conversationId = body.conversation_id || '';
const messageId = body.id || '';
const status = body.status || 'success';
const error = body.error || '';

// Extract variables from output (if any)
const outputVariables = body.outputs || {};
const variables = Object.entries(outputVariables).map(([k, v]) => `${k}: ${v}`).join(', ') || 'none';

return [{
  json: {
    success: status === 'success' && !!answer,
    answer: answer,
    conversation_id: conversationId,
    message_id: messageId,
    status: status,
    variables: variables,
    channel: webhookInput.channel || 'general',
    timestamp: new Date().toISOString()
  }
}];
